import{_ as r,o as t,c as _,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"鬼下属技艺血鬼术-非月之鬼","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/4.综合类/鬼灭之刃-鬼/鬼下属技艺血鬼术-非月之鬼.md","filePath":"4.资源分区/2.改造与功法/改造/4.综合类/鬼灭之刃-鬼/鬼下属技艺血鬼术-非月之鬼.md"}'),o={name:"4.资源分区/2.改造与功法/改造/4.综合类/鬼灭之刃-鬼/鬼下属技艺血鬼术-非月之鬼.md"};function d(l,a,i,p,b,c){return t(),_("div",null,[...a[0]||(a[0]=[e("h1",{id:"鬼下属技艺血鬼术-非月之鬼",tabindex:"-1"},[n("鬼下属技艺血鬼术-非月之鬼 "),e("a",{class:"header-anchor",href:"#鬼下属技艺血鬼术-非月之鬼","aria-label":'Permalink to "鬼下属技艺血鬼术-非月之鬼"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风028")])])],-1),s('<h1 id="鬼下属技艺血鬼术-非月之鬼-1" tabindex="-1">鬼下属技艺血鬼术-非月之鬼 <a class="header-anchor" href="#鬼下属技艺血鬼术-非月之鬼-1" aria-label="Permalink to &quot;鬼下属技艺血鬼术-非月之鬼&quot;">​</a></h1><p>血鬼术-朱纱丸.手球<br> C+1000<br> 某个把自己说死的鬼的血鬼术<br> 能够让自己投出的手球具有极其强大的威力，而且能够一定程度上的自由控制。<br> 你投掷球形物体进行的攻击变为【曲线型】且具有【贯穿】和1点额外的附加成功。你投掷球形物体进行的攻击视为【血鬼术】<br> 由于tmd主神阻止了涩情要素，所以额外从侧胸部分长出手臂的效果被砍掉了。</p><p>血鬼术-矢琶羽.红洁之箭<br> C+1000<br> 某个眼睛长手上的鬼的血鬼术<br> 能够从自己的眼睛里发出具有力量的无实体红色箭矢使目标进行移动的能力。<br> 你可以用眼睛发射出红色的箭矢进行攻击，这种攻击方式以【力量+射击+能量控制+辅助专业：弹道学】进行攻击，具有20M射程，3点武器伤害和一个额外的附加成功，造成立场伤害。<br> 该种攻击方式无法应用于攻击多个单位或者转变为范围攻击的能力。<br> 你可以将箭头方向转化为向上，该次攻击检定不造成伤害，命中后，对方以反射豁免对抗你剩余攻击出目，失败则被你击飞胜出的成功数。这是一个D级创伤来源的击飞效果。<br> 同时的，每轮一次，你可以通过箭头表现出自己的力量，击中目标后你可以用自由动作通过箭头进行一次特殊的拖拽，对方以反射豁免抵抗。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',5)])])}const m=r(o,[["render",d]]);export{f as __pageData,m as default};
